/**
 * Module Loader Admin Service
 *
 * Business logic service for the Module Loader admin module.
 * Provides admin-level module management operations wrapping the kernel ModuleLoader.
 *
 * @module modules/_core/module-loader/module-loader.service
 *
 * @example
 * ```typescript
 * import { ModuleLoaderService } from '@/modules/_core/module-loader/module-loader.service';
 * import { resolve } from '@/core/kernel/container';
 *
 * const moduleService = resolve<ModuleLoaderService>('ModuleLoaderService');
 *
 * // List all modules
 * const modules = await moduleService.listModules();
 *
 * // Activate a module
 * const result = await moduleService.activateModule({ moduleId: 'menu' });
 * ```
 */

import { injectable, inject } from 'tsyringe';

import { TOKENS } from '@/core/kernel/container';
import { ModuleLoader, LoadedModule, ModuleStatus, ModuleCategory } from '@/core/kernel/module-loader';
import { AppException } from '@/core/exceptions/app.exception';
import { EventService } from '@/core/services/event.service';

import type {
  ModuleInfo,
  ModuleSummary,
  ModuleStats,
  ModuleListParams,
  ModuleListResponse,
  ModuleActionResponse,
  ModuleActivateRequest,
  ModuleDeactivateRequest,
  DependencyCheckResult,
  ModuleHealthCheckResult,
} from '@/modules/_core/module-loader/module-loader.types';

import { toModuleInfo, toModuleSummary } from '@/modules/_core/module-loader/module-loader.types';

// -----------------------------------------------------------------------------
// Module Loader Service
// -----------------------------------------------------------------------------

/**
 * Module Loader Admin Service
 *
 * Handles all module management operations for the admin panel:
 * - List and filter modules
 * - Activate/deactivate modules
 * - Check dependencies
 * - Module health checks
 *
 * @example
 * ```typescript
 * @injectable()
 * class AdminController {
 *   constructor(
 *     @inject('ModuleLoaderService') private moduleService: ModuleLoaderService,
 *   ) {}
 *
 *   async getModules() {
 *     return this.moduleService.listModules();
 *   }
 * }
 * ```
 */
@injectable()
export class ModuleLoaderService {
  constructor(
    @inject(TOKENS.ModuleLoader) private readonly moduleLoader: ModuleLoader,
    @inject(TOKENS.EventService) private readonly eventService: EventService
  ) {}

  // ---------------------------------------------------------------------------
  // Read Operations
  // ---------------------------------------------------------------------------

  /**
   * Lists all modules with optional filtering.
   *
   * @param params - Query parameters
   * @returns Module list response with stats
   */
  async listModules(params: ModuleListParams = {}): Promise<ModuleListResponse> {
    let modules = this.moduleLoader.getAllModules();

    // Apply filters
    if (params.category) {
      modules = modules.filter((m) => m.manifest.category === params.category);
    }

    if (params.status) {
      modules = modules.filter((m) => m.status === params.status);
    }

    if (params.isCore !== undefined) {
      modules = modules.filter((m) => m.manifest.core === params.isCore);
    }

    if (params.isEnabled !== undefined) {
      const targetStatus = params.isEnabled ? 'active' : 'disabled';
      modules = modules.filter((m) => (params.isEnabled ? m.status === 'active' : m.status !== 'active'));
    }

    if (params.search) {
      const searchLower = params.search.toLowerCase();
      modules = modules.filter(
        (m) =>
          m.manifest.name.toLowerCase().includes(searchLower) ||
          m.manifest.displayName.toLowerCase().includes(searchLower) ||
          m.manifest.description.toLowerCase().includes(searchLower)
      );
    }

    // Apply sorting
    const sortField = params.sortBy || 'priority';
    const sortOrder = params.sortOrder || 'asc';

    modules.sort((a, b) => {
      let aValue: string | number;
      let bValue: string | number;

      switch (sortField) {
        case 'name':
          aValue = a.manifest.displayName.toLowerCase();
          bValue = b.manifest.displayName.toLowerCase();
          break;
        case 'category':
          aValue = a.manifest.category;
          bValue = b.manifest.category;
          break;
        case 'status':
          aValue = a.status;
          bValue = b.status;
          break;
        case 'priority':
        default:
          aValue = a.manifest.priority;
          bValue = b.manifest.priority;
          break;
      }

      if (aValue < bValue) return sortOrder === 'asc' ? -1 : 1;
      if (aValue > bValue) return sortOrder === 'asc' ? 1 : -1;
      return 0;
    });

    // Convert to ModuleInfo
    const moduleInfos = modules.map((m) => {
      const dependents = this.moduleLoader.getModuleDependents(m.manifest.id);
      return toModuleInfo(m, dependents);
    });

    // Build response
    return {
      modules: moduleInfos,
      stats: params.includeStats !== false ? this.getStats() : this.getStats(),
    };
  }

  /**
   * Lists module summaries for quick display.
   *
   * @returns Array of module summaries
   */
  async listModuleSummaries(): Promise<ModuleSummary[]> {
    const modules = this.moduleLoader.getAllModules();
    return modules.map((m) => {
      const info = toModuleInfo(m);
      return toModuleSummary(info);
    });
  }

  /**
   * Gets module by ID.
   *
   * @param moduleId - Module ID
   * @returns Module info or null
   */
  async getModuleById(moduleId: string): Promise<ModuleInfo | null> {
    const module = this.moduleLoader.getModule(moduleId);
    if (!module) {
      return null;
    }

    const dependents = this.moduleLoader.getModuleDependents(moduleId);
    return toModuleInfo(module, dependents);
  }

  /**
   * Gets module by ID or throws.
   *
   * @param moduleId - Module ID
   * @returns Module info
   * @throws {AppException} If module not found
   */
  async getModuleByIdOrThrow(moduleId: string): Promise<ModuleInfo> {
    const module = await this.getModuleById(moduleId);
    if (!module) {
      throw AppException.moduleNotFound(moduleId);
    }
    return module;
  }

  /**
   * Gets active modules.
   *
   * @returns Array of active module infos
   */
  async getActiveModules(): Promise<ModuleInfo[]> {
    const modules = this.moduleLoader.getActiveModules();
    return modules.map((m) => {
      const dependents = this.moduleLoader.getModuleDependents(m.manifest.id);
      return toModuleInfo(m, dependents);
    });
  }

  /**
   * Gets core modules.
   *
   * @returns Array of core module infos
   */
  async getCoreModules(): Promise<ModuleInfo[]> {
    const modules = this.moduleLoader.getCoreModules();
    return modules.map((m) => {
      const dependents = this.moduleLoader.getModuleDependents(m.manifest.id);
      return toModuleInfo(m, dependents);
    });
  }

  /**
   * Gets modules by category.
   *
   * @param category - Module category
   * @returns Array of module infos
   */
  async getModulesByCategory(category: ModuleCategory): Promise<ModuleInfo[]> {
    const modules = this.moduleLoader.getModulesByCategory(category);
    return modules.map((m) => {
      const dependents = this.moduleLoader.getModuleDependents(m.manifest.id);
      return toModuleInfo(m, dependents);
    });
  }

  /**
   * Gets modules by status.
   *
   * @param status - Module status
   * @returns Array of module infos
   */
  async getModulesByStatus(status: ModuleStatus): Promise<ModuleInfo[]> {
    const modules = this.moduleLoader.getModulesByStatus(status);
    return modules.map((m) => {
      const dependents = this.moduleLoader.getModuleDependents(m.manifest.id);
      return toModuleInfo(m, dependents);
    });
  }

  /**
   * Gets module statistics.
   *
   * @returns Module statistics
   */
  getStats(): ModuleStats {
    const kernelStats = this.moduleLoader.getStats();
    const allModules = this.moduleLoader.getAllModules();

    return {
      total: kernelStats.total,
      byStatus: kernelStats.byStatus,
      byCategory: kernelStats.byCategory,
      active: kernelStats.byStatus.active || 0,
      core: allModules.filter((m) => m.manifest.core).length,
      errors: kernelStats.byStatus.error || 0,
    };
  }

  // ---------------------------------------------------------------------------
  // Activation Operations
  // ---------------------------------------------------------------------------

  /**
   * Activates a module.
   *
   * @param request - Activation request
   * @returns Action response
   *
   * @example
   * ```typescript
   * const result = await moduleService.activateModule({ moduleId: 'menu' });
   * if (result.success) {
   *   console.log('Module activated:', result.module?.id);
   * }
   * ```
   */
  async activateModule(request: ModuleActivateRequest): Promise<ModuleActionResponse> {
    const { moduleId, force } = request;

    // Check module exists
    const module = this.moduleLoader.getModule(moduleId);
    if (!module) {
      throw AppException.moduleNotFound(moduleId);
    }

    // Check if already active
    if (module.status === 'active') {
      return {
        success: true,
        module: await this.getModuleByIdOrThrow(moduleId),
        message: `Module ${moduleId} is already active.`,
      };
    }

    // Check dependencies unless forced
    if (!force) {
      const depCheck = this.checkDependencies(moduleId);
      if (!depCheck.valid) {
        if (depCheck.missing.length > 0) {
          throw AppException.moduleDependencyError(moduleId, depCheck.missing);
        }
        if (depCheck.circular.length > 0) {
          throw AppException.badRequest(
            `Circular dependency detected for module ${moduleId}: ${depCheck.circular.join(', ')}`
          );
        }
      }
    }

    // Perform activation
    const startTime = Date.now();
    const success = await this.moduleLoader.activateModule(moduleId);
    const duration = Date.now() - startTime;

    if (!success) {
      const updatedModule = this.moduleLoader.getModule(moduleId);
      throw AppException.internal(
        `Failed to activate module ${moduleId}: ${updatedModule?.error || 'Unknown error'}`
      );
    }

    // Emit event
    await this.eventService.emitCustom('module.activated', {
      moduleId,
      version: module.manifest.version,
      activatedAt: new Date().toISOString(),
      duration,
      timestamp: new Date().toISOString(),
    });

    const updatedModule = await this.getModuleByIdOrThrow(moduleId);

    return {
      success: true,
      module: updatedModule,
      message: `Module ${moduleId} activated successfully.`,
    };
  }

  /**
   * Deactivates a module.
   *
   * @param request - Deactivation request
   * @returns Action response
   */
  async deactivateModule(request: ModuleDeactivateRequest): Promise<ModuleActionResponse> {
    const { moduleId, force } = request;

    // Check module exists
    const module = this.moduleLoader.getModule(moduleId);
    if (!module) {
      throw AppException.moduleNotFound(moduleId);
    }

    // Core modules cannot be deactivated
    if (module.manifest.core) {
      throw AppException.coreModuleProtected(moduleId);
    }

    // Check if already inactive
    if (module.status !== 'active') {
      return {
        success: true,
        module: await this.getModuleByIdOrThrow(moduleId),
        message: `Module ${moduleId} is already inactive.`,
      };
    }

    // Check dependents unless forced
    const warnings: string[] = [];
    if (!force) {
      const dependents = this.moduleLoader.getModuleDependents(moduleId);
      const activeDependents = dependents.filter(
        (depId) => this.moduleLoader.getModule(depId)?.status === 'active'
      );

      if (activeDependents.length > 0) {
        throw AppException.badRequest(
          `Cannot deactivate ${moduleId}: other active modules depend on it: ${activeDependents.join(', ')}`
        );
      }
    } else {
      const dependents = this.moduleLoader.getModuleDependents(moduleId);
      const activeDependents = dependents.filter(
        (depId) => this.moduleLoader.getModule(depId)?.status === 'active'
      );
      if (activeDependents.length > 0) {
        warnings.push(`Force deactivating with active dependents: ${activeDependents.join(', ')}`);
      }
    }

    // Perform deactivation
    const startTime = Date.now();
    const success = await this.moduleLoader.deactivateModule(moduleId);
    const duration = Date.now() - startTime;

    if (!success) {
      const updatedModule = this.moduleLoader.getModule(moduleId);
      throw AppException.internal(
        `Failed to deactivate module ${moduleId}: ${updatedModule?.error || 'Unknown error'}`
      );
    }

    // Emit event
    await this.eventService.emitCustom('module.deactivated', {
      moduleId,
      version: module.manifest.version,
      deactivatedAt: new Date().toISOString(),
      duration,
      timestamp: new Date().toISOString(),
    });

    const updatedModule = await this.getModuleByIdOrThrow(moduleId);

    return {
      success: true,
      module: updatedModule,
      message: `Module ${moduleId} deactivated successfully.`,
      warnings: warnings.length > 0 ? warnings : undefined,
    };
  }

  // ---------------------------------------------------------------------------
  // Dependency Operations
  // ---------------------------------------------------------------------------

  /**
   * Checks module dependencies.
   *
   * @param moduleId - Module ID to check (optional, checks all if not provided)
   * @returns Dependency check result
   */
  checkDependencies(moduleId?: string): DependencyCheckResult {
    const resolution = this.moduleLoader.resolveDependencies(moduleId ? [moduleId] : undefined);

    // Check for available optional dependencies
    const availableOptional: string[] = [];
    if (moduleId) {
      const module = this.moduleLoader.getModule(moduleId);
      if (module) {
        for (const optDep of module.manifest.dependencies.optional) {
          const depModule = this.moduleLoader.getModule(optDep);
          if (depModule && depModule.status === 'active') {
            availableOptional.push(optDep);
          }
        }
      }
    }

    return {
      valid: resolution.resolved,
      missing: resolution.missing,
      circular: resolution.circular,
      availableOptional,
      loadOrder: resolution.loadOrder,
    };
  }

  /**
   * Gets module dependents (modules that depend on this one).
   *
   * @param moduleId - Module ID
   * @returns Array of dependent module IDs
   */
  getModuleDependents(moduleId: string): string[] {
    return this.moduleLoader.getModuleDependents(moduleId);
  }

  /**
   * Checks if a module is available and active.
   *
   * @param moduleId - Module ID
   * @returns True if module is active
   */
  isModuleActive(moduleId: string): boolean {
    return this.moduleLoader.isModuleActive(moduleId);
  }

  // ---------------------------------------------------------------------------
  // Health Check Operations
  // ---------------------------------------------------------------------------

  /**
   * Performs health check on a module.
   *
   * @param moduleId - Module ID
   * @returns Health check result
   */
  async checkModuleHealth(moduleId: string): Promise<ModuleHealthCheckResult> {
    const module = this.moduleLoader.getModule(moduleId);

    if (!module) {
      return {
        moduleId,
        status: 'unhealthy',
        message: 'Module not found',
        checkedAt: new Date(),
      };
    }

    // Check based on status
    if (module.status === 'error') {
      return {
        moduleId,
        status: 'unhealthy',
        message: module.error || 'Module in error state',
        details: { error: module.error },
        checkedAt: new Date(),
      };
    }

    if (module.status !== 'active') {
      return {
        moduleId,
        status: 'degraded',
        message: `Module not active (status: ${module.status})`,
        details: { status: module.status },
        checkedAt: new Date(),
      };
    }

    // Check dependencies
    const depCheck = this.checkDependencies(moduleId);
    if (!depCheck.valid) {
      return {
        moduleId,
        status: 'degraded',
        message: 'Some dependencies are not satisfied',
        details: {
          missing: depCheck.missing,
          circular: depCheck.circular,
        },
        checkedAt: new Date(),
      };
    }

    return {
      moduleId,
      status: 'healthy',
      message: 'Module is healthy',
      details: {
        version: module.manifest.version,
        loadedAt: module.loadedAt?.toISOString(),
      },
      checkedAt: new Date(),
    };
  }

  /**
   * Performs health check on all active modules.
   *
   * @returns Array of health check results
   */
  async checkAllModulesHealth(): Promise<ModuleHealthCheckResult[]> {
    const activeModules = this.moduleLoader.getActiveModules();
    const results: ModuleHealthCheckResult[] = [];

    for (const module of activeModules) {
      const result = await this.checkModuleHealth(module.manifest.id);
      results.push(result);
    }

    return results;
  }

  // ---------------------------------------------------------------------------
  // Discovery Operations
  // ---------------------------------------------------------------------------

  /**
   * Triggers module discovery (scans for new modules).
   *
   * @returns Array of newly discovered module IDs
   */
  async discoverModules(): Promise<string[]> {
    return this.moduleLoader.discoverModules();
  }

  /**
   * Gets all permissions from active modules.
   *
   * @returns Array of permission strings
   */
  getAllPermissions(): string[] {
    return this.moduleLoader.getAllPermissions();
  }

  /**
   * Gets admin menu items from active modules.
   *
   * @returns Array of admin menu configurations
   */
  getAdminMenuItems(): Array<{ moduleId: string; menu: { label: string; icon?: string; position: number } }> {
    return this.moduleLoader.getAdminMenuItems();
  }
}
